import React, { useState } from 'react';
import "./Task.css";

const Task = ({ task, handleTaskClick, deleteTaskClick, handleTaskDescription }) => {
    const [inputData, setInputData] = useState("");
    const [isEditing, setIsEditing] = useState(false);  // Controla se está editando
    
    const handleInputChange = (newDescription) => {
        setInputData(newDescription.target.value);
    };

    const handleSaveDescription = () => {
        if (inputData.trim() !== '') {
            handleTaskDescription(task.id, inputData);
            setInputData("");
            setIsEditing(false);  // Sai do modo edição
        }
    };

    const handleKeyDown = (button) => {
        if (button.key === 'Enter' && inputData.trim() !== '') {
            handleTaskDescription(task.id, inputData);
            setInputData("");
            setIsEditing(false);  // Sai do modo edição
        }
    };

    const startEditing = () => {
        setInputData(task.description || '');  // Carrega descrição atual para edição
        setIsEditing(true);
    };

    return (
        <div
            className="task-container"
            style={task.completed ? { borderLeft: '6px solid #d400ff' } : {}}
        >
            <div className="task-title">
                {/* Título da tarefa */}
                <div onClick={() => handleTaskClick(task.id)}>
                    {task.title}
                </div>

                {/* Área da descrição - alterna entre visualização e edição */}
                <div className="task-description">
                    {isEditing ? (
                        // MODO EDIÇÃO: mostra input
                        <div>
                            <input
                                onChange={handleInputChange}
                                value={inputData}
                                onKeyDown={handleKeyDown}
                                className="add-task-description"
                                type="text"
                                placeholder="Digite a descrição..."
                                autoFocus
                                onBlur={() => {
                                    // Se sair do input sem salvar, volta ao modo visualização
                                    if (!inputData.trim()) {
                                        setIsEditing(false);
                                    }
                                }}
                            />
                        </div>
                    ) : (
                        // MODO VISUALIZAÇÃO: mostra texto (se houver) ou opção de adicionar
                        <div 
                            className={`description-text ${task.description ? '' : 'empty'}`}
                            onClick={startEditing}
                        >
                            {task.description ? (
                                <>
                                    {task.description}
                                    <span className="edit-hint"></span>
                                </>
                            ) : (
                                <span className="add-hint">+ Clique para adicionar descrição</span>
                            )}
                        </div>
                    )}
                </div>
            </div>

            <div onClick={() => deleteTaskClick(task.id)}>
                X
            </div>
        </div>
    );
};

export default Task;
